base = r"C:\Users\2121\AppData\Roaming\TRAE SOLO CN\ModularData\ai-agent\work-mode-projects\6a3ed37f1ac00f6e4879b1bd\chronos-app\public\data\narratives"

xuanzang = {"eraId":"sui-tang","eraName":"隋唐","playerRole":"玄奘","acts":[{"id":"act-1","title":"少年出家","isKeyAct":False,"sceneDescription":"隋朝末年，河南陈留陈氏家中，少年陈祎自幼聪慧过人，对佛法有异于常人的悟性。兄长在洛阳净土寺出家为僧，常带回佛经给弟弟阅读。少年陈祎读经入迷，渐渐萌生了出家修行的念头。","npcDialogues":[{"speaker":"兄长陈素","text":"祎弟，你对佛法的领悟远超同龄人。如果你真的有此志向，为兄支持你。","avatar":"素"},{"speaker":"净土寺方丈","text":"这孩子根器深厚，若能潜心修行，日后必成大器。","avatar":"丈"}],"dialogues":[{"id":"d1","text":"兄长，我已决定出家修行。佛法博大精深，我要穷尽一生去参悟。","speaker":"我","avatar":"奘","score":90,"triggeredEvent":"出家修行","historicalNote":"玄奘十三岁在洛阳净土寺出家，法名玄奘。他少年时期便展现出超凡的佛学天赋，很快便在佛门中崭露头角。","consequence":"你剃度出家，法名玄奘。从此你全身心投入佛法研究，少年老成的你在佛门中很快脱颖而出。"},{"id":"d2","text":"我想先多读些佛经，了解更多宗派的教义，再决定是否出家。","speaker":"我","avatar":"奘","score":80,"triggeredEvent":"广泛研读","historicalNote":"玄奘出家前确实研读了大量佛经，对当时各宗派的学说都有深入了解。这为他日后西行求法奠定了基础。","consequence":"你广泛研读各种佛经，对各宗派的学说有了全面的了解。你发现不同经典之间有很多矛盾，这激发了你西行求法的念头。"},{"id":"d3","text":"我要走遍天下名刹，向最博学的高僧请教佛法真谛。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"遍访名师","historicalNote":"玄奘在出国前遍访国内名师，但他发现国内佛学各派说法不一，经典翻译也存在诸多问题，这才下定决心西行求法。","consequence":"你遍访国内高僧大德，虚心请教。但不同宗派的学说互相矛盾，让你深感困惑。你决定亲自去天竺寻求答案。"},{"id":"d4","text":"我要学习梵文，将来如果能去天竺取经，不懂梵文怎么行？","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"学习梵文","historicalNote":"玄奘确实精通梵文，这不仅帮助他在天竺求学，也为他后来翻译佛经提供了坚实的语言基础。","consequence":"你刻苦学习梵文，掌握了这门通往佛法本源的语言。这为日后的西行和翻译工作打下了坚实基础。"},{"id":"d5","text":"天下大乱，百姓受苦。我虽出家，但也不能对世人的苦难视而不见。","speaker":"我","avatar":"奘","score":78,"triggeredEvent":"慈悲为怀","historicalNote":"玄奘一生慈悲为怀，他在西行途中和归国后都尽力帮助遇到的困难之人。","consequence":"你在乱世中坚持修行，同时以慈悲之心帮助周围的人。佛家的慈悲精神成为你一生的信条。"},{"id":"d6","text":"这些佛经翻译得不够准确，我总觉得原文的深意没有完全传达出来。","speaker":"我","avatar":"奘","score":92,"triggeredEvent":"发现翻译问题","historicalNote":"玄奘正是因为发现国内佛经翻译存在大量问题，各宗派各执一词，才下定决心西行取经，寻求原始梵文经典。","consequence":"你发现现有佛经翻译质量参差不齐，各宗派各执一词。你下定决心，要亲自去天竺取回原典，还佛法以本来面目。"}],"nextActId":"act-2"},{"id":"act-2","title":"决心西行","isKeyAct":True,"sceneDescription":"大唐贞观年间，你已成长为一位博学的高僧。然而国内佛学各派纷争不休，经典的翻译更是问题重重。你下定决心西行天竺，去佛陀的故乡寻求佛法真谛。但朝廷严禁百姓私自出境，你的申请未获批准。前方是漫漫黄沙和万里关山，你面临人生中最大的抉择。","npcDialogues":[{"speaker":"僧友","text":"玄奘法师，西行路途遥远艰险，大漠戈壁九死一生。您确定要冒这个险吗？","avatar":"僧"},{"speaker":"边境守将","text":"朝廷有令，严禁私自出关。法师若无通关文牒，不得出境！","avatar":"将"}],"dialogues":[{"id":"d1","text":"宁可就西而死，岂能东归而生！佛法真谛在前方等我，纵有千难万险，在所不辞！","speaker":"我","avatar":"奘","score":95,"triggeredEvent":"决意西行","historicalNote":"玄奘毅然不顾朝廷禁令踏上了西行之路。'宁可就西而死，岂能东归而生'的壮语展现了他求法的坚定决心。","consequence":"你义无反顾地踏上了西行之路。从长安出发，穿越河西走廊，翻越葱岭，向天竺进发。这一走就是十七年。"},{"id":"d2","text":"我先暗中准备行装和物资，等时机合适再秘密出发。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"秘密准备","historicalNote":"玄奘做了充分准备工作，包括收集路线情报、准备干粮和饮水工具等。他选择了在朝廷管控最松的时候出发。","consequence":"你暗中准备了充足的物资和路线情报，在适当的时机悄然离开长安，踏上了西行的征程。"},{"id":"d3","text":"我在沙漠中向佛祖祈祷，求他指引我走出这片死亡之地。","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"虔诚祈祷","historicalNote":"玄奘在大漠中的虔诚祈祷是《大唐慈恩寺三藏法师传》中记载的真实情节。","consequence":"你虔诚祈祷后心神安定了许多。凭借直觉和经验，你选择了正确的方向，最终走出了大漠。"},{"id":"d4","text":"我应该趁天黑凉爽的时候赶路，白天在沙丘下躲避烈日。","speaker":"我","avatar":"奘","score":82,"triggeredEvent":"夜间行路","historicalNote":"玄奘确实采用了夜间赶路的策略来穿越沙漠，这是沙漠生存的智慧。","consequence":"你白天躲避烈日，夜间赶路，成功节省了体力。几天后你终于走出了大漠，看到了前方的绿洲。"},{"id":"d5","text":"我带了一匹老马，据说它曾穿越过这片沙漠。它的直觉比我可靠。","speaker":"我","avatar":"奘","score":86,"triggeredEvent":"信赖老马","historicalNote":"玄奘在大漠中依靠一匹识途的老马找到了水源。这个故事记录在《大慈恩寺三藏法师传》中。","consequence":"你放开缰绳让老马自由行走。老马凭直觉带你找到了一处野泉，你得以补充水分，最终穿越了大漠。"},{"id":"d6","text":"我把自己的经历记录下来，将来如果有人要走这条路，就不会像我这样困难了。","speaker":"我","avatar":"奘","score":80,"triggeredEvent":"记录路途","historicalNote":"玄奘在《大唐西域记》中详细记录了西行路线和沿途地理情况，为后人留下了珍贵的地理资料。","consequence":"你在艰难的旅途中坚持记录地理和见闻，这些记录后来成为《大唐西域记》的重要素材。"}],"nextActId":"act-3"},{"id":"act-3","title":"抵达天竺","isKeyAct":False,"sceneDescription":"经过三年的艰苦跋涉，你终于到达了梦寐以求的天竺。这里是佛陀的故乡，佛教的发源地。从雪山到恒河，从王舍城到鹿野苑，你怀着无比崇敬的心情朝拜了佛教圣地。天竺的佛学氛围让你如鱼得水，你开始在各处游学。","npcDialogues":[{"speaker":"天竺高僧","text":"来自大唐的法师？你的梵文说得极好！大唐居然有如此博学的僧人，真是令人敬佩。","avatar":"天"},{"speaker":"那烂陀寺住持","text":"玄奘法师，我们那烂陀寺是天竺最大的佛学中心。欢迎你来做客，与我们交流学问。","avatar":"住"}],"dialogues":[{"id":"d1","text":"佛陀当年在菩提树下悟道，我今日站在这里，心中无比崇敬。我要精进修行，不负此行。","speaker":"我","avatar":"奘","score":90,"triggeredEvent":"朝拜圣地","historicalNote":"玄奘在天竺朝拜了菩提伽耶、鹿野苑、蓝毗尼等佛教圣地，这些经历加深了他对佛法的理解和感悟。","consequence":"你怀着虔诚之心朝拜了各处佛教圣地，每一处都让你的佛法修为更加精深。你深感此行不虚。"},{"id":"d2","text":"天竺各宗派的学问博大精深，我要一一学习比较，找到最接近佛法的真谛。","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"遍学天竺","historicalNote":"玄奘在天竺学习了五年多，遍访各地高僧，学习了各种佛教学说，最终成为天竺最博学的佛学大师之一。","consequence":"你游历天竺各地，广泛学习各种佛教学说。你惊人的学习能力和博闻强记让天竺僧人惊叹不已。"},{"id":"d3","text":"那烂陀寺是天竺最高佛学府，我一定要去那里求学。","speaker":"我","avatar":"奘","score":92,"triggeredEvent":"求学那烂陀","historicalNote":"玄奘在那烂陀寺学习了五年，师从戒贤大师学习瑜伽行派。那烂陀寺当时有万余名僧人，是天竺最大的佛学研究中心。","consequence":"你进入那烂陀寺，师从戒贤大师深入学习。在那烂陀寺的五年学习让你成为天竺最杰出的佛学大师之一。"},{"id":"d4","text":"我在天竺也要记录下沿途的见闻和风土人情，这些知识对大唐也很重要。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"记录风物","historicalNote":"玄奘在《大唐西域记》中详细记录了一百三十多个国家和地区的地理、历史、文化和宗教情况。","consequence":"你沿途详细记录了各国的地理、历史和风俗。这些记录后来成为《大唐西域记》的核心内容。"},{"id":"d5","text":"我要在天竺收集各种佛经原本，这些梵文经典在国内根本看不到。","speaker":"我","avatar":"奘","score":87,"triggeredEvent":"收集经书","historicalNote":"玄奘在天竺收集了大量梵文经典，共计六百五十七部。这些经典成为他归国后翻译的主要资料。","consequence":"你广泛收集各种梵文佛经，手抄了数百部珍贵经典。这些经书是你此行最重要的收获。"},{"id":"d6","text":"我在这里要虚心学习，同时也要让天竺人了解大唐的文化和佛法。","speaker":"我","avatar":"奘","score":83,"triggeredEvent":"文化交流","historicalNote":"玄奘在天竺不仅学习佛法，也向天竺人介绍了大唐文化。他是中印文化交流史上最重要的人物之一。","consequence":"你在学习中向天竺人介绍了大唐文化，促进了中印两国的文化交流。天竺人对大唐产生了浓厚的兴趣。"}],"nextActId":"act-4"},{"id":"act-4","title":"曲女城辩论","isKeyAct":True,"sceneDescription":"天竺戒日王为你举办了一场盛大的法会，邀请天竺各国高僧和学者齐聚曲女城。数万人围观之下，你以精妙的逻辑和渊博的学识，舌战群儒。如果你赢了，你的名声将响彻天竺。","npcDialogues":[{"speaker":"戒日王","text":"玄奘法师，这场辩论是天竺佛学界最盛大的活动。你作为大唐高僧，能否让我们见识一下你的学问？","avatar":"戒"},{"speaker":"辩论对手","text":"这位大唐法师不过是个外国人，他怎么可能比我们天竺的高僧更有学问？","avatar":"对"}],"dialogues":[{"id":"d1","text":"贫僧以佛法为证，以真理为据。如果有人说得有理，贫僧甘拜下风。若无人能驳倒我的论点，就请以我为胜！","speaker":"我","avatar":"奘","score":95,"triggeredEvent":"立论挑战","historicalNote":"玄奘在曲女城大会上立下论点，悬挂于门外。五日内无人能驳倒他，声名震动整个天竺。","consequence":"你当众立论，将论点悬挂于会场门外。五天过去了，天竺各地的学者无人能驳倒你。你获得了空前的胜利。"},{"id":"d2","text":"佛法不分国界，真理不分种族。贫僧愿以最诚挚的态度与各位高僧交流切磋。","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"诚意辩论","historicalNote":"玄奘在天竺的辩论始终以诚意和学术态度进行，不以言语压人，而是以理服人。","consequence":"你以诚恳的态度和精妙的辩论赢得了在场所有人的敬佩。你的佛学修养让天竺学者叹服。"},{"id":"d3","text":"我先阐述我在那烂陀寺学到的瑜伽行派核心教义，请各位批评指正。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"阐述教义","historicalNote":"玄奘在曲女城大会上详细阐述了唯识学的核心教义，展现了他深厚的佛学功底和清晰的逻辑思维。","consequence":"你条理清晰地阐述了瑜伽行派的教义，语言精妙，逻辑严密。与会者都被你的学识深深折服。"},{"id":"d4","text":"我不仅讲大乘佛法，对小乘经典也有深入研究。佛法是一体的，不应互相排斥。","speaker":"我","avatar":"奘","score":90,"triggeredEvent":"融通大小乘","historicalNote":"玄奘在佛学上的一大贡献是融通了大小乘各派的学说，这种开放态度在天竺学界引起了广泛赞誉。","consequence":"你对大小乘佛法的融通理解让天竺学者耳目一新。你的博学和包容赢得了各派学者的尊重。"},{"id":"d5","text":"辩论不仅是比学问，更是寻求真理的过程。无论结果如何，我都感谢这次交流的机会。","speaker":"我","avatar":"奘","score":82,"triggeredEvent":"以和为贵","historicalNote":"玄奘的学术风格以和平、理性著称，他在天竺的辩论从不以攻击他人为目的，而是追求真理。","consequence":"你的温和态度和渊博学识让辩论成为一场和谐的学术交流。与会者对你充满敬意。"},{"id":"d6","text":"我已经准备了十八部论著，涵盖佛学的各个方面。请各位逐一审阅。","speaker":"我","avatar":"奘","score":87,"triggeredEvent":"展示论著","historicalNote":"玄奘在天竺期间撰写了《会宗论》等佛学论著，展现了融通各派学说的独特见解。","consequence":"你展示的论著涵盖面广、论点精妙。天竺学者审阅后无不信服，称赞你是当世佛学第一人。"}],"nextActId":"act-5"},{"id":"act-5","title":"载誉归来","isKeyAct":False,"sceneDescription":"在天竺求学十七年后，你带着六百五十七部梵文佛经和满满的学问踏上了归途。戒日王和各国高僧依依不舍，送你东归。归途中你经过于阗，上书唐太宗报告了自己的经历。太宗大喜，下诏命你回国。","npcDialogues":[{"speaker":"戒日王","text":"玄奘法师，天竺舍不得你走啊！希望你回国后继续弘扬佛法，造福苍生。","avatar":"戒"},{"speaker":"唐太宗","text":"玄奘法师！朕久闻你在天竺的事迹，真是大唐的骄傲！朕要亲自接见你！","avatar":"宗"}],"dialogues":[{"id":"d1","text":"陛下，臣西行求法十七年，带回佛经六百五十七部。这些是真正的佛法宝藏，臣愿为陛下和大唐百姓翻译讲解。","speaker":"我","avatar":"奘","score":92,"triggeredEvent":"面见太宗","historicalNote":"玄奘归国后受到唐太宗的热烈欢迎。太宗亲自接见了他，并支持他翻译佛经的事业。","consequence":"唐太宗对你的壮举极为赞赏，下诏在长安为你修建译经院。你开始了紧张的翻译工作。"},{"id":"d2","text":"这些年在天竺的见闻，我已写成《大唐西域记》，献给陛下参考。","speaker":"我","avatar":"奘","score":90,"triggeredEvent":"献上西域记","historicalNote":"玄奘口述的《大唐西域记》记录了一百三十多个国家的情况，成为研究古代中亚和南亚的重要文献。","consequence":"太宗对《大唐西域记》赞不绝口。这部著作至今仍是历史学和地理学的重要参考。"},{"id":"d3","text":"陛下，我想在大慈恩寺设立译经院，集中最好的学者一起翻译佛经。","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"设立译经院","historicalNote":"玄奘在大慈恩寺设立了译经院，组织了庞大的翻译团队。他采用'新译'方法，翻译质量远超前人。","consequence":"太宗批准了你的请求。你组织了一百多位学者开始翻译佛经，这是中国历史上规模最大的佛经翻译工程。"},{"id":"d4","text":"天竺戒日王对我的帮助非常大，我要向朝廷报告天竺的友好态度。","speaker":"我","avatar":"奘","score":82,"triggeredEvent":"外交贡献","historicalNote":"玄奘的西行不仅是一次宗教之旅，也是一次重要的外交和文化交流活动。","consequence":"你向朝廷详细报告了天竺各国的态度，促进了中印之间的友好往来。你的西行成为中外文化交流的典范。"},{"id":"d5","text":"我要把在天竺学到的所有知识都整理出来，翻译成中文，让大唐百姓都能学习。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"翻译经书","historicalNote":"玄奘归国后十九年间翻译了七十五部佛经，共一千三百三十五卷，是中国历史上翻译佛经最多的人。","consequence":"你日以继夜地翻译佛经，在十九年间完成了七十五部、一千三百三十五卷的翻译。你的翻译质量空前绝后。"},{"id":"d6","text":"西行十七年，终于回来了。长安还是那座长安，但我已不再是当年的我了。","speaker":"我","avatar":"奘","score":80,"triggeredEvent":"感慨归来","historicalNote":"玄奘归国时已年近半百，十七年的西行让他从一个青年僧人成长为一代佛学大师。","consequence":"你站在长安城门前，回望漫漫西行路。十七年的历练让你从一位求法僧成长为一代佛学宗师。"}],"nextActId":"act-6"},{"id":"act-6","title":"译经弘法","isKeyAct":False,"sceneDescription":"长安大慈恩寺内，译经院日夜灯火通明。你已年逾花甲，但译经工作从未停歇。十九年间，你翻译了七十五部、一千三百三十五卷佛经。你还创立了法相宗，培养了大量弟子。晚年你偶感风寒，卧床不起。你一生的宏愿已经完成。","npcDialogues":[{"speaker":"弟子窥基","text":"师父，您要注意身体啊。您已经翻译了这么多经书，该休息了。","avatar":"窥"},{"speaker":"玄奘","text":"我这一辈子，从长安到天竺，从天竺再回长安，千山万水，九死一生。值得吗？值得。","avatar":"奘"}],"dialogues":[{"id":"d1","text":"贫僧此生，西行求法，归国译经，虽历尽艰辛，但无一日虚度。佛法已在大唐生根发芽，贫僧死而无憾。","speaker":"我","avatar":"奘","score":95,"triggeredEvent":"圆满一生","historicalNote":"玄奘是中国佛教史上最伟大的翻译家和求法僧之一。他的西行求法和归国译经对中华文化产生了深远影响。","consequence":"你含笑回顾一生，从出家到西行，从那烂陀到长安译经院。千山万水，九死一生，但你无怨无悔。"},{"id":"d2","text":"弟子们，你们要继续译经弘法。贫僧翻译了一千三百多卷，但还有更多经书等待翻译。","speaker":"我","avatar":"奘","score":88,"triggeredEvent":"托付弟子","historicalNote":"玄奘培养了大量弟子，如窥基、圆测等，他们继承了他的学说，将法相宗发扬光大。","consequence":"你的弟子们继承了译经和弘法的事业。法相宗在他们手中继续发展。"},{"id":"d3","text":"我的《大唐西域记》记录了一百多个国家的情况，后世去天竺的人可以参考。","speaker":"我","avatar":"奘","score":90,"triggeredEvent":"西域记传世","historicalNote":"《大唐西域记》不仅是佛学著作，更是珍贵的地理和历史文献。近代考古学家据此找到了许多印度古代遗址。","consequence":"你的《大唐西域记》成为后世了解古代中亚和南亚的宝贵资料。近代考古学家据此找到了那烂陀寺等遗址。"},{"id":"d4","text":"我的翻译方法被称为'新译'，比前人的翻译更加准确。希望后人能继续用这种方法译经。","speaker":"我","avatar":"奘","score":85,"triggeredEvent":"新译之法","historicalNote":"玄奘创立的'新译'方法讲究忠实原文、文辞优美，翻译质量远超前人。","consequence":"你的'新译'方法成为后世佛经翻译的典范，影响了一千多年的佛经翻译事业。"},{"id":"d5","text":"我最大的遗憾，是没能把所有想翻译的经典都翻译完。但一个人的力量终究是有限的。","speaker":"我","avatar":"奘","score":80,"triggeredEvent":"遗憾未完","historicalNote":"玄奘确实还有很多想翻译的经典未能完成。他在玉华寺译经时还在赶工，直到生命的最后时刻。","consequence":"你带着未竟的遗憾离去，但你已完成的工作已经超越了前人。"},{"id":"d6","text":"千山万水，九死一生。从长安到天竺，再从天竺回长安。而佛法，永远在路上。","speaker":"我","avatar":"奘","score":93,"triggeredEvent":"玄奘永恒","historicalNote":"玄奘西行取经的故事激励了后世无数人。《西游记》就是以他为原型创作的。而他真实的一生比任何传奇都更加壮丽。","consequence":"你安然圆寂，享年六十五岁。后世将你的故事演绎为《西游记》，唐僧取经成为中华文化中最经典的传奇之一。"}],"nextActId":None}]}

sushi = {"eraId":"song-yuan","eraName":"宋元","playerRole":"苏轼","acts":[{"id":"act-1","title":"少年成才","isKeyAct":False,"sceneDescription":"四川眉山，苏家少年苏轼自幼聪颖好学，与弟弟苏辙在父亲苏洵的教导下读书。二十一岁时，他与弟弟一同进京赶考，一篇《刑赏忠厚之至论》震惊了主考官欧阳修。","npcDialogues":[{"speaker":"苏洵","text":"轼儿，读书做学问，最重要的是诚实。你天赋虽高，但不可恃才傲物。","avatar":"洵"},{"speaker":"苏辙","text":"哥哥，你的文章写得真好，这次进京赶考，一定能高中！","avatar":"辙"}],"dialogues":[{"id":"d1","text":"父亲放心，我一定会好好考试，为苏家争光。但更重要的是，我要写出真正有见地的文章。","speaker":"我","avatar":"轼","score":92,"triggeredEvent":"进京赶考","historicalNote":"苏轼二十一岁进京赶考，主考官欧阳修读到他的文章后大为赞叹，误以为是曾巩所写。苏轼从此名动京城。","consequence":"你在科举中一举成名。欧阳修惊为天人，说'这个老夫必须让路，让此人出人头地'。你从此名动天下。"},{"id":"d2","text":"弟弟，我们一起进京赶考，一起为苏家争光！","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"兄弟同考","historicalNote":"苏轼和苏辙兄弟同榜进士及第，'三苏'之名从此传遍天下。父子三人同列'唐宋八大家'。","consequence":"你与弟弟同榜高中，'三苏'名扬天下。眉山苏家成为中国文学史上的传奇。"},{"id":"d3","text":"我要学习各种经史子集，不能只限于科举。真正的学问在书本之外。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"博学多才","historicalNote":"苏轼不仅是文学家，还是书法家、画家、美食家，精通诗词书画和医药。他的多才多艺在中国文化史上罕有匹敌。","consequence":"你广泛涉猎各种学问，成为宋代文化最耀眼的明星。"},{"id":"d4","text":"欧阳修大人说我的文章好，但这只是开始。我要写出更多更好的作品。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"谦虚进取","historicalNote":"欧阳修对苏轼的赞赏是真诚的。苏轼确实没有辜负欧阳修的期望，成为中国文学史上的巨匠。","consequence":"你没有因为一次成功而骄傲，反而更加努力。这种谦虚进取的态度赢得了前辈的赏识。"},{"id":"d5","text":"父亲的教导我铭记在心。做人做事，都要以诚为本。","speaker":"我","avatar":"轼","score":80,"triggeredEvent":"铭记父训","historicalNote":"苏洵对苏轼的教育深刻影响了他的性格。苏轼虽然才华横溢，但始终保持着正直诚实的品格。","consequence":"父亲的教诲成为你一生的行为准则。你在官场上始终保持着正直的品格。"},{"id":"d6","text":"我想多读一些道家的书，学会超脱名利，这样在仕途上才能保持清醒。","speaker":"我","avatar":"轼","score":83,"triggeredEvent":"道家思想","historicalNote":"苏轼深受儒释道三家思想影响，他的文学作品中融合了儒家的责任感、道家的超脱和佛家的空灵。","consequence":"你开始接触道家和佛家思想，这使你的文学创作和精神境界更加开阔。"}],"nextActId":"act-2"},{"id":"act-2","title":"变法之争","isKeyAct":True,"sceneDescription":"宋神宗起用王安石推行新法。你虽赞同改革初衷，但认为新法执行操之过急，弊端丛生。你上书直言进谏，反对激进变法，与王安石产生了严重的政治分歧。","npcDialogues":[{"speaker":"王安石","text":"子瞻，你虽然才华出众，但政治上太保守了。大宋积贫积弱，不变法怎么行？","avatar":"石"},{"speaker":"司马光","text":"子瞻，你做得对。王安石的新法确实弊端很多，我们一定要据理力争。","avatar":"光"}],"dialogues":[{"id":"d1","text":"安石兄，变法本身没有错，但执行方法不对。你不能不顾百姓的死活强推新法啊！","speaker":"我","avatar":"轼","score":90,"triggeredEvent":"直言进谏","historicalNote":"苏轼并非完全反对变法，而是反对新法执行中的急躁冒进。他上书神宗，指出新法的弊端。","consequence":"你上书直言，指出新法的种种弊端。神宗虽然欣赏你的才华，但对你的政见不以为然。"},{"id":"d2","text":"我不属于任何一党，我只说我认为对的话。不管新党旧党，谁对我就支持谁。","speaker":"我","avatar":"轼","score":92,"triggeredEvent":"独立立场","historicalNote":"苏轼一生不依附任何党派，他既反对王安石的激进变法，也反对司马光的全面废除新法。这种独立的立场使他两面不讨好。","consequence":"你坚持独立的政治立场，既不盲从新党也不依附旧党。虽然两面受压，但赢得了正直之士的尊敬。"},{"id":"d3","text":"新法推行过程中确实出了很多问题，我亲眼看到百姓因此受苦。我必须说出真相。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"为民请命","historicalNote":"苏轼在各地任职时亲眼看到了新法执行中给百姓带来的苦难，他在诗文中多次反映这些问题。","consequence":"你将新法执行中的问题如实反映，虽然触怒了变法派，但你的良心是清白的。"},{"id":"d4","text":"也许我应该主动请求外调，离开朝堂这个是非之地。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"请求外调","historicalNote":"苏轼确实多次请求外调，先后在杭州、密州、徐州等地任职。在地方上他政绩卓著，深受百姓爱戴。","consequence":"你请求外调到地方任职，在各地做出了出色的政绩，深受百姓爱戴。"},{"id":"d5","text":"我给神宗上书，详细分析新法的利弊，希望他能听取不同意见。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"上书皇帝","historicalNote":"苏轼多次上书神宗皇帝，分析新法的利弊。他的奏疏文笔优美、论理精辟。","consequence":"你的奏疏文采斐然、分析透彻，但神宗最终没有采纳你的意见。"},{"id":"d6","text":"朝堂之争越演越烈，我该找个时机退隐山林，专心写作。","speaker":"我","avatar":"轼","score":78,"triggeredEvent":"萌生退意","historicalNote":"苏轼确实有过退隐的念头，但儒家的入世精神让他始终无法真正远离政治。","consequence":"你虽然萌生退意，但心中始终放不下天下苍生。你选择继续坚持自己的政治理想。"}],"nextActId":"act-3"},{"id":"act-3","title":"乌台诗案","isKeyAct":True,"sceneDescription":"元丰二年，御史台从你的诗文中摘取断章取义的句子，指控你讽刺新法、诽谤朝廷。你被逮捕入狱，关押了一百三十天。牢中阴暗潮湿，生死未卜。写诗竟然也能成为杀头的罪名。","npcDialogues":[{"speaker":"狱卒","text":"苏大人，你在诗中写的那些话，御史台认定是讽刺朝廷。你好好想想怎么为自己辩护吧。","avatar":"狱"},{"speaker":"弟弟苏辙","text":"哥哥！我正在四处营救你！你一定要挺住啊！","avatar":"辙"}],"dialogues":[{"id":"d1","text":"我写诗不过是抒发个人情感，何曾想过讽刺朝廷？但既然身陷囹圄，我也只能坦然面对。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"坦然面对","historicalNote":"乌台诗案是北宋最著名的文字狱之一。苏轼在狱中以为必死无疑，甚至给弟弟写了绝命诗。","consequence":"你在狱中坦然面对生死，写下了'与君世世为兄弟'的绝命诗。你的坦然最终打动了神宗。"},{"id":"d2","text":"我给弟弟写信交代后事，万一我出不去了，请他照顾好家人。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"狱中遗书","historicalNote":"苏轼在狱中确实给弟弟苏辙写了绝命诗，表达了对弟弟的深情和对人世的眷恋。","consequence":"你给弟弟写了绝命诗。苏辙读到后痛哭流涕，四处奔走营救你。"},{"id":"d3","text":"曹太后、王安石等人都上书为我求情，希望朝廷能从轻发落。","speaker":"我","avatar":"轼","score":80,"triggeredEvent":"多方营救","historicalNote":"乌台诗案中，多位朝中重臣为苏轼求情，包括已经退隐的王安石。","consequence":"在好友和旧交的营救下，神宗终于动了恻隐之心。你免于死罪，被贬为黄州团练副使。"},{"id":"d4","text":"在狱中这一百多天，我反复思考人生的意义。名利富贵不过是过眼云烟，唯有内心的平静最重要。","speaker":"我","avatar":"轼","score":90,"triggeredEvent":"狱中顿悟","historicalNote":"乌台诗案是苏轼人生的重要转折点。出狱后他的思想更加豁达，文学创作达到了更高的境界。","consequence":"你在狱中的深刻反思让你的人生态度发生了根本转变。你不再执着于功名利禄，而是追求内心的自在和超脱。"},{"id":"d5","text":"这场牢狱之灾让我看清了官场的险恶。以后写诗要更加谨慎了。","speaker":"我","avatar":"轼","score":75,"triggeredEvent":"教训深刻","historicalNote":"乌台诗案对苏轼的打击很大，但并没有真正改变他的性格。他后来仍然坚持写诗和说真话。","consequence":"你虽然受到教训，但骨子里的豪放和真诚无法改变。你依然会写出真性情的诗文。"},{"id":"d6","text":"那些人断章取义，故意曲解我的诗文。我要为自己辩白！","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"为自己辩白","historicalNote":"苏轼在狱中确实为自己做了辩护，但御史台认定他的诗文确实含有讽刺新法的内容。","consequence":"你为自己做了有力的辩白，指出那些指控都是断章取义。但政治审判不讲究逻辑。"}],"nextActId":"act-4"},{"id":"act-4","title":"赤壁赋诗","isKeyAct":True,"sceneDescription":"被贬黄州后，你住在一处简陋的小院中。长江之畔，赤壁之下，你与友人泛舟饮酒，写下了《念奴娇·赤壁怀古》和前后《赤壁赋》等千古名篇。你开始自号'东坡居士'。","npcDialogues":[{"speaker":"好友佛印","text":"子瞻兄，黄州虽然偏远，但这里的山水确实不错。你在这里反而写出了更好的作品。","avatar":"印"},{"speaker":"黄州百姓","text":"苏大人，您虽然是被贬来的，但您为我们做了不少好事，我们都感谢您。","avatar":"民"}],"dialogues":[{"id":"d1","text":"大江东去，浪淘尽，千古风流人物。人生如梦，一尊还酹江月！","speaker":"我","avatar":"轼","score":95,"triggeredEvent":"赤壁怀古","historicalNote":"苏轼在黄州写下了《念奴娇·赤壁怀古》和前后《赤壁赋》等散文名篇。黄州时期是他的文学创作最高峰。","consequence":"你在黄州的长江边写下了这些不朽名篇。逆境反而释放了你的文学才华。'东坡居士'从此响彻天下。"},{"id":"d2","text":"一蓑烟雨任平生！人生的坎坷不过如此，我何惧之有？","speaker":"我","avatar":"轼","score":93,"triggeredEvent":"旷达人生","historicalNote":"苏轼在黄州写下了《定风波》中的名句'一蓑烟雨任平生'，展现了他面对逆境时豁达乐观的人生态度。","consequence":"你以旷达的心态面对逆境。你从政治家蜕变为一位更加超然的文学巨匠。"},{"id":"d3","text":"被贬黄州反而是件好事。远离朝堂纷争，我可以专心写作，亲近自然。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"因祸得福","historicalNote":"黄州贬谪虽然政治上是低谷，却是苏轼文学创作的最高峰。","consequence":"你在黄州过着简朴但自在的生活，文学创作进入了前所未有的巅峰期。"},{"id":"d4","text":"我在东坡开荒种地，自给自足。劳动虽然辛苦，但很充实。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"东坡耕种","historicalNote":"苏轼在黄州确实在东坡开荒种地，自号'东坡居士'。","consequence":"你亲自动手开荒种地。简朴的生活让你更加接近百姓。'东坡居士'的名号由此而来。"},{"id":"d5","text":"虽然生活拮据，但黄州的猪肉很便宜。我来研究一下怎么做更好吃！","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"东坡肉","historicalNote":"苏轼在黄州发明了'东坡肉'等美食。他不仅是文学大家，也是饮食文化史上的重要人物。","consequence":"你研究出了美味的红烧猪肉做法，后来被称为'东坡肉'。即使是逆境中，你也能发现生活的乐趣。"},{"id":"d6","text":"我常常与佛印禅师讨论佛理，佛法让我的心境更加平和。","speaker":"我","avatar":"轼","score":86,"triggeredEvent":"参禅悟道","historicalNote":"苏轼与佛印禅师是至交好友，两人的禅机对答成为后世传诵的佳话。","consequence":"你与佛印的交流让你的精神境界更加开阔。儒释道三家思想在你身上完美融合。"}],"nextActId":"act-5"},{"id":"act-5","title":"再贬惠州","isKeyAct":False,"sceneDescription":"旧党掌权后你被召回朝廷，但反对全面废除新法的立场又得罪了旧党。新党重新得势后，你再次被贬，这次是更远的惠州。年近六旬的你不得不再次南下。","npcDialogues":[{"speaker":"朝中旧友","text":"子瞻，你怎么又得罪了人？这次被贬到惠州，可比黄州远多了。","avatar":"友"},{"speaker":"苏轼","text":"日啖荔枝三百颗，不辞长作岭南人！惠州虽然偏远，但也不是什么荒蛮之地。","avatar":"轼"}],"dialogues":[{"id":"d1","text":"日啖荔枝三百颗，不辞长作岭南人！被贬到岭南又怎样？这里的荔枝甜得很！","speaker":"我","avatar":"轼","score":92,"triggeredEvent":"乐观面对","historicalNote":"苏轼在惠州写下了'日啖荔枝三百颗'的名句，展现了他在逆境中始终乐观豁达的人生态度。","consequence":"你以乐观的态度面对惠州的生活。惠州的百姓也因为你而名留青史。"},{"id":"d2","text":"我为官一方，就要造福一方。在惠州我也要为百姓做实事。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"造福惠州","historicalNote":"苏轼在惠州期间帮助当地百姓修桥铺路、引水灌溉，深受百姓爱戴。","consequence":"你在惠州期间为当地做了不少好事。百姓对你感激不尽。"},{"id":"d3","text":"朝中的党争越来越激烈，我两派都得罪了，看来这辈子是注定要被贬来贬去的。","speaker":"我","avatar":"轼","score":80,"triggeredEvent":"感叹党争","historicalNote":"苏轼一生都在新旧党争中辗转，他不依附任何一方的独立立场使他两面不讨好。","consequence":"你对朝中的党争深感厌倦，但并不后悔自己的立场。"},{"id":"d4","text":"惠州的风土人情与中原大不相同，我来好好体验一下这里的生活。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"融入岭南","historicalNote":"苏轼在惠州期间积极融入当地生活，品尝岭南美食，体验当地风俗。","consequence":"你深入体验岭南的生活，发现了许多北方人不知道的美食和风俗。"},{"id":"d5","text":"我写给弟弟的信中详细记录了在惠州的生活。虽然苦，但也有苦中作乐的滋味。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"书信报平安","historicalNote":"苏轼与弟弟苏辙的兄弟情深是文学史上最动人的篇章。兄弟俩一生相互扶持。","consequence":"你给弟弟写信报平安，字里行间既有对生活的热爱，也有对亲人的思念。"},{"id":"d6","text":"也许我该彻底放下仕途的执念，安心做个文人，享受生活中的每一天。","speaker":"我","avatar":"轼","score":83,"triggeredEvent":"放下执念","historicalNote":"苏轼多次贬谪后确实越来越超脱于政治之外，但他的人生态度始终是积极的。","consequence":"你逐渐放下了对政治的执着，将全部精力投入到文学创作和生活中。"}],"nextActId":"act-6"},{"id":"act-6","title":"流放海南","isKeyAct":False,"sceneDescription":"六十二岁的你再次被贬，这次是海南岛儋州——宋代最偏远的流放地。渡海时你写好了遗书，以为此去必死无疑。然而海南的风土和淳朴的百姓给了你意外的温暖。你在儋州开办学堂，教化当地百姓。","npcDialogues":[{"speaker":"儿子苏过","text":"父亲，海南太远了，条件又差。您年事已高，这趟去恐怕……","avatar":"过"},{"speaker":"儋州百姓","text":"苏大人，您来我们这里真是太好了！我们从来没有见过这么有学问的人！","avatar":"黎"}],"dialogues":[{"id":"d1","text":"九死南荒吾不恨，兹游奇绝冠平生！海南虽远，但这一生的经历足以自慰。","speaker":"我","avatar":"轼","score":93,"triggeredEvent":"不恨南荒","historicalNote":"苏轼在海南写下了'九死南荒吾不恨，兹游奇绝冠平生'的诗句，展现了在最艰苦环境中依然保持乐观的精神。","consequence":"你在海南虽然艰苦，但始终保持着乐观豁达的心态。你将这次贬谪视为人生最后一次奇妙的旅行。"},{"id":"d2","text":"我要在儋州办学堂，教当地的孩子读书识字。这里的人不应该因为地处偏远就被遗忘。","speaker":"我","avatar":"轼","score":92,"triggeredEvent":"儋州办学","historicalNote":"苏轼在儋州创办了载酒堂，教授当地学子。海南至今还保留着对他的纪念。他被尊为开发海南文化的先驱。","consequence":"你在儋州创办了学堂，教授当地学子读书识字。你的到来极大地促进了海南的文化发展。"},{"id":"d3","text":"海南的风土人情独特，我要把这里的一切都记录下来。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"记录海南","historicalNote":"苏轼在海南期间详细记录了当地的风土人情、物产资源。这些是研究宋代海南的重要史料。","consequence":"你将海南的见闻详细记录，这些文字成为后世了解宋代海南的宝贵资料。"},{"id":"d4","text":"儿子，跟着我受苦了。但你也能从中学到很多课本上学不到的东西。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"父子情深","historicalNote":"苏轼贬谪海南时，小儿子苏过始终陪伴在身边。父子二人在海南相依为命。","consequence":"苏过始终陪伴在你身边。父子二人在海南相依为命，这段经历让你们的感情更加深厚。"},{"id":"d5","text":"这里的老百姓淳朴善良，对我很好。我虽然是被流放的，但并不觉得孤独。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"百姓之恩","historicalNote":"海南百姓对苏轼非常敬爱，他们不把他当作罪人，而是当作一位有学问的长者来尊敬。","consequence":"海南百姓的淳朴和善良让你深受感动。他们在你困难时给予了无私的帮助。"},{"id":"d6","text":"在海岛上，我的思想反而更加开阔了。天地之大，何尝不是一种修行？","speaker":"我","avatar":"轼","score":86,"triggeredEvent":"海岛修行","historicalNote":"苏轼在海南期间的精神境界达到了前所未有的高度。他在逆境中完成的文学作品充满了对人生的深刻感悟。","consequence":"你在海南的修行让你的精神境界更加开阔。逆境中的领悟融入了你的文学作品。"}],"nextActId":"act-7"},{"id":"act-7","title":"北归之途","isKeyAct":False,"sceneDescription":"在海南流放数年后，朝廷终于下达了赦免令。你北归途中，沿途受到了百姓和文人的热烈欢迎。然而多年的流放已经严重损害了你的健康。从海南到常州，你走走停停。","npcDialogues":[{"speaker":"沿途百姓","text":"苏大人回来了！我们给您准备了最好的酒菜！","avatar":"民"},{"speaker":"弟子","text":"先生，您一路辛苦了。您的身体看起来不太好。","avatar":"弟"}],"dialogues":[{"id":"d1","text":"心似已灰之木，身如不系之舟。问汝平生功业，黄州惠州儋州。这一生，无怨无悔。","speaker":"我","avatar":"轼","score":95,"triggeredEvent":"总结一生","historicalNote":"苏轼北归途中写下了自题画像诗'问汝平生功业，黄州惠州儋州'，将三次贬谪之地视为一生最重要的功业。","consequence":"你以超然的态度回顾一生，将最痛苦的三次贬谪视为自己最重要的'功业'。这种豁达让所有人都为之动容。"},{"id":"d2","text":"北归途中看到山河依旧，心中感慨万千。这些年的经历，都化为了诗。","speaker":"我","avatar":"轼","score":88,"triggeredEvent":"北归诗作","historicalNote":"苏轼北归途中创作了不少诗篇，既是对人生的总结，也是对未来的展望。","consequence":"你在北归途中写下了一系列感慨万千的诗作。这些作品是你一生的完美注脚。"},{"id":"d3","text":"沿途受到这么多人欢迎，我很感动。原来这么多年来，我的诗文一直被人们记着。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"百姓爱戴","historicalNote":"苏轼虽然屡遭贬谪，但在百姓中享有极高的声望。他的诗文在民间广为流传。","consequence":"沿途百姓对你的热情欢迎让你深受感动。你的诗文一直在温暖着人们的心灵。"},{"id":"d4","text":"我的身体越来越差了，恐怕走不了多远了。但能死在回家的路上，也是一种幸运。","speaker":"我","avatar":"轼","score":80,"triggeredEvent":"身体衰竭","historicalNote":"苏轼北归途中身体确实严重衰竭，最终在常州病逝。","consequence":"你拖着病体继续北归，但体力已经越来越不支。你知道自己时日无多了，但内心十分平静。"},{"id":"d5","text":"我把这些年在各地积累的学问和见闻整理一下，留给后人参考。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"整理遗作","historicalNote":"苏轼在北归途中仍然坚持整理自己的作品。","consequence":"你在最后的日子里整理自己的作品和笔记。这些珍贵的文字是你留给后人的文化遗产。"},{"id":"d6","text":"弟弟，我终于要回来了。虽然走不动了，但能离你近一些，也算是一种安慰。","speaker":"我","avatar":"轼","score":83,"triggeredEvent":"思念弟弟","historicalNote":"苏轼与弟弟苏辙兄弟情深，苏轼去世后苏辙将他的灵柩运回眉山安葬。","consequence":"你在生命的最后日子里最想念的就是弟弟。虽然未能再相见，但你们兄弟的情谊超越了生死。"}],"nextActId":"act-8"},{"id":"act-8","title":"东坡永存","isKeyAct":False,"sceneDescription":"建中靖国元年，你病逝于常州，享年六十五岁。临终前你对守在身边的儿子说：'我一生没有做错什么，不需要忏悔。'从眉山少年到东坡居士，从朝廷命官到天涯流人，你用一生诠释了什么是真正的旷达和自由。","npcDialogues":[{"speaker":"苏过","text":"父亲，您还有什么话要嘱咐的吗？","avatar":"过"},{"speaker":"后人","text":"一蓑烟雨任平生——苏轼的一生告诉我们，真正的自由不在外界，而在心中。","avatar":"后"}],"dialogues":[{"id":"d1","text":"我这一生，不求高官厚禄，只求活得真实。文章千古事，得失寸心知。","speaker":"我","avatar":"轼","score":95,"triggeredEvent":"坦荡一生","historicalNote":"苏轼是中国文化史上最全面、最具影响力的文人之一。他的诗词、散文、书法、绘画都达到了极高成就。","consequence":"你含笑而逝。你的诗文跨越千年，至今仍在人们心中激荡。你是中国文化永远的骄傲——东坡居士，千古风流。"},{"id":"d2","text":"告诉弟弟，我不后悔这一生的任何选择。该说的说了，该写的写了，够了。","speaker":"我","avatar":"轼","score":92,"triggeredEvent":"无怨无悔","historicalNote":"苏轼临终时表示自己一生没有做错什么。他的一生虽然坎坷，但活得坦荡、真实、精彩。","consequence":"你带着无怨无悔的从容离去。你的弟弟苏辙悲痛万分，但他知道，你的一生是完整而精彩的。"},{"id":"d3","text":"希望后人读我的诗文时，能感受到那种无论顺境逆境都保持乐观的精神。","speaker":"我","avatar":"轼","score":90,"triggeredEvent":"精神遗产","historicalNote":"苏轼'一蓑烟雨任平生'的精神成为中华文化中最珍贵的精神财富之一。","consequence":"你的旷达精神跨越千年，激励着无数在困境中的人。每当有人读到你的诗文，都会从中获得前行的力量。"},{"id":"d4","text":"我的诗文风格多变，既有豪放也有婉约。人生也是如此，不必拘泥于一种态度。","speaker":"我","avatar":"轼","score":85,"triggeredEvent":"多元精神","historicalNote":"苏轼的文学风格丰富多彩，既有大江东去的豪放，也有十年生死两茫茫的婉约。","consequence":"你的多元文学风格展现了人生的丰富性。后人从你的作品中看到了人生的各种可能。"},{"id":"d5","text":"我虽然被贬来贬去，但每到一处都交了不少朋友。这些友情是我最珍贵的财富。","speaker":"我","avatar":"轼","score":82,"triggeredEvent":"珍重友情","historicalNote":"苏轼一生交友广泛，从文坛巨匠到普通百姓，他都真诚相待。","consequence":"你留给后人的不仅是诗文，还有真诚待人的态度。你的友情故事成为后世的典范。"},{"id":"d6","text":"人生如逆旅，我亦是行人。这趟人间之行，我走得很尽兴。","speaker":"我","avatar":"轼","score":93,"triggeredEvent":"东坡永恒","historicalNote":"苏轼是中国文学史上最伟大的全才文人。他的'东坡精神'——旷达、乐观、真诚，成为中华文化中最珍贵的精神遗产之一。","consequence":"你坦然走完了人间的旅程。千年之后，你的名字仍然照亮着中华文明的天空。东坡居士，千古风流！"}],"nextActId":None}]}

